import { use, useEffect, useState } from "react";

const allProducts = 'https://dummyjson.com/products?limit=0'
const paginatedProducts = 'https://dummyjson.com/products'
const paginatedQueryParam = (limit,skipResult) => `?limit=${limit}&skip=${skipResult}`

async function getData(skipResult) {
    const resp = await fetch(paginatedProducts)
    const data = await resp.json()
    return data
}
function useData(page = 1) {
    const [skipResult, setSkipResult] = useState(0)
    const [data, setData] = useState({
        loading: false,
        error: null,
        tableData: null
    })

   async function fetchData() {
    setData((prev) => {
        return {
          ...prev,
          loading: true
        }
    })
    try{
        const data = await getData(skipResult)
        setData((prev) => {
        return {
          ...prev,
          tableData: data?.products
        }
        })
    } catch (err) {
setData((prev) => {
        return {
          ...prev,
          error: 'Error'
        }
        })
    } finally {
        setData((prev) => {
        return {
          ...prev,
          loading: false
        }
        })
    }
   }
    useEffect(() => {
      fetchData()
    },[skipResult])
    return tableData
}

export default useData
